430:     this.validateLoadResult(url, format);
431:     const translator = getTranslators().get(format);
432: 
433:     if (!translator) {
434:       throw new ERR_UNKNOWN_MODULE_FORMAT(format, url);
435:     }
436: 
437:     return FunctionPrototypeCall(translator, this, url, source, isMain);
